try {
  const input = $input.item.json;

  // Base de Dados Estruturada (Hardcoded)
  const db = {
    hospedagem: {
      fevereiro: { fds: 450, sem: 400, extra: 100 },
      marco: { fds: 400, sem: 350, extra: 70 },
      abril: { fds: 350, sem: 300, extra: 70 },
      maio: { fds: 300, sem: 250, extra: 70 },
      loft: 50,
      pet: 100
    },
    passeios: {
      ilhas: { valor: 150 }, // Assumindo baixa por padrão, a IA não precisa distinguir pra complexidade agora
      gruta: { valor: 150 },
      meia_volta: { valor: 120 },
      volta_ilha: { valor: 200 },
      super_aventureiro: { valor: 250 },
      lopes_mendes: { valor: 90 }
    }
  };

  let total = 0;
  let descritivo = [];

  // Tratamento de Hospedagem
  if (input.tipo_calculo === 'hospedagem') {
    const mesTarget = input.mes ? input.mes.toLowerCase().replace('ç', 'c') : 'maio';
    const tarifa = db.hospedagem[mesTarget] || db.hospedagem['maio'];

    const adultosPagantes = Math.max(1, input.adultos || 2);
    const diasFDS = input.dias_fds || 0;
    const diasSem = input.dias_semana || 0;
    const totalDias = diasFDS + diasSem;

    // Regra Tarifa Base (Até 2 pessoas)
    const baseFDS = diasFDS * tarifa.fds;
    const baseSem = diasSem * tarifa.sem;
    let valorAcomodacao = baseFDS + baseSem;

    // Hospedes Extras (Acima de 2 adultos)
    if (adultosPagantes > 2) {
       const extrasAdultos = adultosPagantes - 2;
       valorAcomodacao += (extrasAdultos * tarifa.extra * totalDias);
    }

    // Tratamento de Crianças (Hospedagem)
    let valorCriancas = 0;
    if (input.idades_criancas && Array.isArray(input.idades_criancas)) {
       input.idades_criancas.forEach(idade => {
          if (idade > 5 && idade <= 10) {
             valorCriancas += ((tarifa.extra / 2) * totalDias);
          } else if (idade > 10) {
             valorCriancas += (tarifa.extra * totalDias);
          }
       });
    }
    valorAcomodacao += valorCriancas;

    // Desconto Prime Gourmet (30% sobre acomodação)
    if (input.prime_gourmet) {
      valorAcomodacao = valorAcomodacao * 0.70;
      descritivo.push('Desconto Prime Gourmet (-30%) aplicado.');
    }

    // Extras Fixos (Loft e Pet)
    let valorAdicionais = 0;
    if (input.extras && Array.isArray(input.extras)) {
      if (input.extras.includes('loft')) {
        valorAdicionais += (db.hospedagem.loft * totalDias);
      }
      if (input.extras.includes('pet')) {
        valorAdicionais += db.hospedagem.pet; // Taxa unica
      }
    }

    total = valorAcomodacao + valorAdicionais;
    descritivo.unshift(`Orçamento Hospedagem (${totalDias} noites em ${mesTarget})`);
  }

  // Tratamento de Passeios
  else if (input.tipo_calculo === 'passeio') {
    const passTarget = input.passeio_alvo ? input.passeio_alvo.toLowerCase() : 'super_aventureiro';
    const tarifaPass = db.passeios[passTarget] ? db.passeios[passTarget].valor : 250;

    const adultosPass = input.adultos || 2;
    let valorPass = adultosPass * tarifaPass;

    // Tratamento de Crianças (Passeio)
    if (input.idades_criancas && Array.isArray(input.idades_criancas)) {
       input.idades_criancas.forEach(idade => {
          if (idade >= 5 && idade <= 8) {
             valorPass += (tarifaPass * 0.50);
          } else if (idade > 8) {
             valorPass += tarifaPass;
          }
       });
    }
    total = valorPass;
    descritivo.unshift(`Orçamento Passeio (${passTarget})`);
  }

  // Regra Obrigatória: Sinal de 30%
  const sinal = total * 0.30;
  const resto = total - sinal;

  return [{
    json: {
      sucesso: true,
      mensagem: "Cálculo executado com perfeição. Repassar valores ao cliente.",
      detalhes: descritivo.join(' | '),
      valor_total: total.toFixed(2),
      valor_sinal: sinal.toFixed(2),
      valor_restante_checkin: resto.toFixed(2)
   }
  }];

} catch (error) {
  return [{
    json: {
      sucesso: false,
      mensagem: "A Tool não conseguiu calcular. Você deve ter passado um JSON ou variável inválida. Avise o cliente e escale para o Humano.",
      erro: error.message
    }
  }];
}
